-- ----------------------------------------------------------------------------
-- PlatformNaviation: Table: PlatformNaviation
-- ----------------------------------------------------------------------------
CREATE TABLE platform_naviation (
  platform_naviation_id               TEXT                 PRIMARY KEY,
  display_name                        TEXT                ,
  route                               TEXT                ,
  description                         TEXT                ,
  sort_order                          NUMERIC             ,
  parent_route_key                    TEXT                ,                     -- Route key of parent nav node (empty for top-level)
  route_key                           TEXT                ,                     -- Stable dot-delimited slug, e.g. checklists.score
  nav_level                           TEXT                ,                     -- Hierarchy level
  role_visibility                     TEXT                ,                     -- Comma-separated canonical roles that can see this nav item. Tokens: REP / MANAGER / OPERATIONS / ADMIN (uppercase). ADMIN visibility implies OPERATIONS.
  primary_table                       TEXT                ,                     -- Backing table name
  erb_package                         TEXT                ,                     -- FK -> ERBPackages.ERBPackageId. The package that owns this route.
  primary_view                        TEXT                ,                     -- Backing vw_* view
  business_rule_refs                  TEXT                ,                     -- CSV of rule codes shown on this route
  build_phase                         INTEGER             ,                     -- Build order phase 1-7
  status                              TEXT                ,                     -- Implementation status
  is_licensed                         BOOLEAN             ,                     -- This route's own licensing flag. When false, the route is hidden from non-Effortless users regardless of its package (used to fence off the Effortless Elements admin tooling). Blank/true = licensed.
  requires_claim_context              BOOLEAN             ,                     -- True if route needs an active claim/checklist context
  pin_to_top                          BOOLEAN             ,                     -- Pin this route to the very top of its nav level, before SortOrder
  is_dynamic                          BOOLEAN             ,                     -- True if path contains :params
  icon_hint                           TEXT                ,                     -- Optional icon name for UI
  admin_crud                          TEXT                ,                     -- Admin CRUD grant for this route (contains C/R/U/D). NULL/empty = role cannot access this route. Seeded from RoleVisibility.
  manager_crud                        TEXT                ,                     -- Manager CRUD grant for this route (contains C/R/U/D). NULL/empty = role cannot access this route. Seeded from RoleVisibility.
  representative_crud                 TEXT                ,                     -- Representative CRUD grant for this route (contains C/R/U/D). NULL/empty = role cannot access this route. Seeded from RoleVisibility.
  external_llm_crud                   TEXT                ,                     -- External LLM CRUD grant for this route (contains C/R/U/D). NULL/empty = role cannot access this route. Seeded from RoleVisibility.
  created_at                          TIMESTAMPTZ         ,                     -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  created_by                          TEXT                ,                     -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  modified_at                         TIMESTAMPTZ         ,                     -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  modified_by                         TEXT                ,                     -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  modified_by_model                   TEXT                                      -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
);
COMMENT ON COLUMN platform_naviation.parent_route_key IS 'Route key of parent nav node (empty for top-level)';
COMMENT ON COLUMN platform_naviation.route_key IS 'Stable dot-delimited slug, e.g. checklists.score';
COMMENT ON COLUMN platform_naviation.nav_level IS 'Hierarchy level';
COMMENT ON COLUMN platform_naviation.role_visibility IS 'Comma-separated canonical roles that can see this nav item. Tokens: REP / MANAGER / OPERATIONS / ADMIN (uppercase). ADMIN visibility implies OPERATIONS.';
COMMENT ON COLUMN platform_naviation.primary_table IS 'Backing table name';
COMMENT ON COLUMN platform_naviation.erb_package IS 'FK -> ERBPackages.ERBPackageId. The package that owns this route.';
COMMENT ON COLUMN platform_naviation.primary_view IS 'Backing vw_* view';
COMMENT ON COLUMN platform_naviation.business_rule_refs IS 'CSV of rule codes shown on this route';
COMMENT ON COLUMN platform_naviation.build_phase IS 'Build order phase 1-7';
COMMENT ON COLUMN platform_naviation.status IS 'Implementation status';
COMMENT ON COLUMN platform_naviation.is_licensed IS 'This route''s own licensing flag. When false, the route is hidden from non-Effortless users regardless of its package (used to fence off the Effortless Elements admin tooling). Blank/true = licensed.';
