-- ----------------------------------------------------------------------------
-- Jurisdictions: Table: Jurisdictions
-- ----------------------------------------------------------------------------
CREATE TABLE jurisdictions (
  jurisdiction_id                     TEXT                 PRIMARY KEY,
  state                               TEXT                ,
  notes                               TEXT                ,
  jurisdiction_type                   TEXT                ,
  code                                TEXT                ,                     -- Short human code for the jurisdiction, e.g. 'CA-LA', 'NY-NYC', 'TX-AUS'.
  display_name                        TEXT                ,                     -- Full readable jurisdiction name, e.g. 'Los Angeles County, California'.
  days_to_respond                     INTEGER             ,                     -- Number of days after issuance the driver has to respond (pay or request a hearing) before default judgment.
  days_to_pay_after_ruling            INTEGER             ,                     -- Number of days after a guilty ruling (or after issuance if not contested) the fine is due before it is late.
  late_penalty_pct                    NUMERIC             ,                     -- Percentage surcharge added to the assessed amount once a payment is late (e.g. 0.25 = 25%).
  days_late_to_collections            INTEGER             ,                     -- Number of days a payment may remain late before it is referred to collections.
  point_suspension_threshold          INTEGER             ,                     -- Total active license points at or above which a driver's license is suspended in this jurisdiction.
  point_warning_threshold             INTEGER             ,                     -- Total active license points at or above which a driver receives an advisory warning (below suspension).
  traffic_school_point_cap            INTEGER             ,                     -- Maximum violation points for which traffic school is offered as a points-reducing option in this jurisdiction.
  parent_jurisdiction                 TEXT                ,                     -- The parent jurisdiction in the hierarchy (e.g., US for California). Empty for root jurisdictions like countries.
  child_jurisdictions                 TEXT                ,                     -- The child jurisdictions under this parent (e.g., all 50 states roll up to US).
  jurisdiction_rules                  TEXT                ,
  source_documents                    TEXT                ,                     -- Source documents (e.g. Appeal Board Decision PDFs) downloaded for this jurisdiction; rules are extracted from them.
  created_at                          TIMESTAMPTZ         ,                     -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  created_by                          TEXT                ,                     -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  modified_at                         TIMESTAMPTZ         ,                     -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  modified_by                         TEXT                ,                     -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  modified_by_model                   TEXT                                      -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
);
