-- ----------------------------------------------------------------------------
-- AssistantTurns: Table: AssistantTurns
-- ----------------------------------------------------------------------------
CREATE TABLE assistant_turns (
  assistant_turn_id                   TEXT                 PRIMARY KEY,         -- Slug/uuid PK for the turn.
  created_at                          TIMESTAMPTZ         ,                     -- When the turn was submitted (ISO timestamp).
  current_state_key                   TEXT                ,                     -- Final state of the chat-agent machine for this turn: 'responding' (success) or 'failed'. Bare StateKey value.
  question_kind                       TEXT                ,                     -- Classifier branch: rulebook / company / claim.
  route_path                          TEXT                ,                     -- Concrete app path the turn was active on, e.g. '/claims/zamora-thiago-2026-01-30'.
  route_key                           TEXT                ,                     -- PlatformNaviation route_key in scope when known (raw string, not an FK — concrete instance paths need not match a nav row).
  citation                            TEXT                ,                     -- FK to the Citation this assistant turn concerns.
  app_user_id                         TEXT                ,                     -- App user who asked (raw id; linked logically).
  ai_model                            TEXT                ,                     -- FK -> AiModels.AiModelId — model that answered.
  model_pricing_version               TEXT                ,                     -- FK -> ModelPricingVersions.ModelPricingVersionId — the exact pricing version used to bill this turn (snapshotted so historical cost is stable even after prices change).
  user_message                        TEXT                ,                     -- The user's question text for this turn.
  assistant_reply                     TEXT                ,                     -- The assistant's reply text.
  raw_exchange                        TEXT                ,                     -- Full request/response metadata as raw JSON (messages, system-prompt kind, usage block, finish reason, latency).
  input_tokens                        INTEGER             ,                     -- Total prompt/input tokens (including any cached).
  cached_input_tokens                 INTEGER             ,                     -- Portion of input tokens served from prompt cache (billed at the cached rate).
  output_tokens                       INTEGER             ,                     -- Completion/output tokens.
  created_by                          TEXT                ,                     -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  modified_at                         TIMESTAMPTZ         ,                     -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  modified_by                         TEXT                ,                     -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  modified_by_model                   TEXT                                      -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
);
