COMMENT ON COLUMN assistant_turns.current_state_key IS 'Final state of the chat-agent machine for this turn: ''responding'' (success) or ''failed''. Bare StateKey value.';
COMMENT ON COLUMN assistant_turns.question_kind IS 'Classifier branch: rulebook / company / claim.';
COMMENT ON COLUMN assistant_turns.route_path IS 'Concrete app path the turn was active on, e.g. ''/claims/zamora-thiago-2026-01-30''.';
