CREATE TABLE erb_packages (
  erb_package_id                      TEXT                 PRIMARY KEY,         -- PK — kebab logical key for the package.
  title                               TEXT                ,                     -- Human-readable package name.
  description                         TEXT                ,                     -- What this package/product module does, in prose.
  status                              TEXT                ,                     -- Lifecycle: SHIPPED / in-progress / PLANNED / DEPRECATED.
  is_active                           BOOLEAN             ,                     -- Master switch. When false, every table/field/route owned by this package reports PackageIsActive=false and the UI hides it pervasively (rows stay in the DB).
  is_licensed                         BOOLEAN             ,                     -- Licensing master switch. When false, every route owned by this package reports PackageIsLicensed=false and is hidden from non-Effortless users (rows stay in the DB; Effortless staff still see them). Separate axis from IsActive.
  sort_order                          NUMERIC             ,                     -- Display order in a generated spec / nav.
  is_key                              BOOLEAN             ,                     -- Star flag — marks the headline packages so users can focus on the top platform capabilities amid the long tail. Blank/false = ordinary packages.
  source_text                         TEXT                ,                     -- Supporting/original source text (markdown) describing the package.
  source_files                        TEXT                ,                     -- Comma-separated repo-relative path(s) of the source document(s).
  erb_features                        TEXT                ,                     -- Reverse link to ERBFeatures — child feature rows belonging to this package (1->many).
  created_at                          TIMESTAMPTZ         ,                     -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  created_by                          TEXT                ,                     -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  modified_at                         TIMESTAMPTZ         ,                     -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  modified_by                         TEXT                ,                     -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  modified_by_model                   TEXT                                      -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
);
