CREATE TABLE erb_features (
  erb_feature_id                      TEXT                 PRIMARY KEY,         -- PK — kebab logical key for the feature.
  route                               TEXT                ,                     -- Platform route this ERBFeatures row navigates to. Defaults to the "feature-detail" detail route; its template feeds RelativePath.
  erb_package                         TEXT                ,                     -- FK -> ERBPackages.ERBPackageId. The package this feature belongs to (many features -> one package).
