CREATE TABLE erb_tables (
  erb_table_id                        TEXT                 PRIMARY KEY,         -- PK = the table name as it appears in the rulebook.
  table_name                          TEXT                ,                     -- Table name.
  description                         TEXT                ,                     -- Table description (copied from the rulebook; refreshed additively by build).
  erb_package                         TEXT                ,                     -- FK -> ERBPackages.ERBPackageId. The package that owns this table.
  platform                            TEXT                ,                     -- FK -> Platforms.PlatformId. The platform this table belongs to.
  is_licensed                         BOOLEAN             ,                     -- This table's own licensing flag. When false, the table is hidden from non-Effortless users regardless of its package (used to fence off Effortless Elements meta/catalog tables). Blank/true = licensed.
  field_count                         NUMERIC             ,                     -- Number of fields (refreshed by build).
  is_catalog                          BOOLEAN             ,                     -- TRUE for the meta/catalog tables themselves.
  admin_crud                          TEXT                ,                     -- Admin CRUD grant for this table (contains C/R/U/D). NULL inherits Roles.DefaultCRUD for Admin.
  admin_where                         TEXT                ,                     -- Admin row-access policy (SQL WHERE fragment) limiting which rows of this table Admin may see. NULL = no row restriction. Source for the RLS plan.
  manager_crud                        TEXT                ,                     -- Manager CRUD grant for this table (contains C/R/U/D). NULL inherits Roles.DefaultCRUD for Manager.
  manager_where                       TEXT                ,                     -- Manager row-access policy (SQL WHERE fragment) limiting which rows of this table Manager may see. NULL = no row restriction. Source for the RLS plan.
  representative_crud                 TEXT                ,                     -- Representative CRUD grant for this table (contains C/R/U/D). NULL inherits Roles.DefaultCRUD for Representative.
  representative_where                TEXT                ,                     -- Representative row-access policy (SQL WHERE fragment) limiting which rows of this table Representative may see. NULL = no row restriction. Source for the RLS plan.
  external_llm_crud                   TEXT                ,                     -- External LLM CRUD grant for this table (contains C/R/U/D). NULL inherits Roles.DefaultCRUD for External LLM.
  external_llm_where                  TEXT                ,                     -- External LLM row-access policy (SQL WHERE fragment) limiting which rows of this table External LLM may see. NULL = no row restriction. Source for the RLS plan.
  admin_is_redacted                   BOOLEAN             ,                     -- Per-table redaction override for Admin. NULL = inherit Roles.IsRedactedRole. TRUE/FALSE explicitly sets whether this role is redacted FOR THIS TABLE (drives the default field access on "<Field>Redacted"-paired fields).
  manager_is_redacted                 BOOLEAN             ,                     -- Per-table redaction override for Manager. NULL = inherit Roles.IsRedactedRole. TRUE/FALSE explicitly sets whether this role is redacted FOR THIS TABLE (drives the default field access on "<Field>Redacted"-paired fields).
  representative_is_redacted          BOOLEAN             ,                     -- Per-table redaction override for Representative. NULL = inherit Roles.IsRedactedRole. TRUE/FALSE explicitly sets whether this role is redacted FOR THIS TABLE (drives the default field access on "<Field>Redacted"-paired fields).
  external_llm_is_redacted            BOOLEAN             ,                     -- Per-table redaction override for External LLM. NULL = inherit Roles.IsRedactedRole. TRUE/FALSE explicitly sets whether this role is redacted FOR THIS TABLE (drives the default field access on "<Field>Redacted"-paired fields).
  created_at                          TIMESTAMPTZ         ,                     -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  created_by                          TEXT                ,                     -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  modified_at                         TIMESTAMPTZ         ,                     -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  modified_by                         TEXT                ,                     -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  modified_by_model                   TEXT                                      -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
);
