-- ----------------------------------------------------------------------------
CREATE TABLE subject_state_instances (
  subject_state_instance_id           TEXT                 PRIMARY KEY,         -- PK: ssi-{subject-table}-{subject-id}-{state-key}-{sequence-index}.
  state_machine                       TEXT                ,                     -- FK -> StateMachines.StateMachineId.
  subject_table_name                  TEXT                ,                     -- Polymorphic table name, e.g. Citations or Hearings.
  subject_id                          TEXT                ,                     -- Polymorphic PK of the subject row.
  state_key                           TEXT                ,                     -- The machine state entered by this occupancy record.
  entered_at                          TIMESTAMPTZ         ,                     -- Timestamp when this state was entered.
  exited_at                           TIMESTAMPTZ         ,                     -- Timestamp when the subject left this state. NULL while current.
  sequence_index                      NUMERIC             ,                     -- 1-based position on this subject's path through the machine.
  prior_instance                      TEXT                ,                     -- Self-FK -> SubjectStateInstances.SubjectStateInstanceId — the previous occupancy in this subject's chain. NULL for the initial state.
  entered_via_transition              TEXT                ,                     -- FK -> StateTransitions.StateTransitionId — the edge event that created this occupancy.
